    for(i in 1:100){LAM[i] = h(i)}
    lam = LAM[!duplicated(LAM)];
    cut = t[!duplicated(LAM)];
    ans = list(); ans$lam = lam; ans$cut = cut;
    return(ans)
  }

function_codes.finalize.nphDesign:
finalize.nphDesign = function(T=c(29, 45.5), n=300, r=1, dist=dist, accr=accr, alphabeta=alphabeta,
                     f.ws = list(IA1 = list(lr), FA=list(lr, fh01)),
                     show.setting="Y", non.centrality = "Heetal2021"){
  
  #Number of analyses
  K = length(f.ws)
  J = lengths(f.ws) 
  
  #Construct distribution functions h0, S0, h1, S1
  if(dist$control$dist=="exponential"){
    lam0 = log(2) / dist$control$median
    if (dist$crossover$status=="N"){
      h0 = function(t){lam0}
      S0 =  function(t){1-pexp(t, rate=lam0)}
    } else {
      h0 = function(t){
        HR = dist$exp$HR; HRx = dist$crossover$HRx
        lt = as.numeric(t < dist$crossover$Tx)
        return(lam0 * lt + HR / HRx * lam0 * (1 - lt))
      } 
      S0 = function(t){
        HR = dist$exp$HR; HRx = dist$crossover$HRx; Tx = dist$crossover$Tx
        lt = as.numeric(t < Tx)
        c0 = exp(-Tx*lam0*(1 - HR / HRx))
        return(exp(-lam0*t)*lt + c0*exp(-HR/HRx * lam0 * t) * (1 - lt))
      }
    }  
  }
  
  h1 = function(t){
    delay = dist$exp$delay; HR = dist$exp$HR; lt = as.numeric(t < delay)
    lam0 * lt + HR * lam0 * (1 - lt)
  }
  S1 = function(t){
    delay = dist$exp$delay; HR = dist$exp$HR; lt = as.numeric(t < delay)
    c1 = exp(-delay*lam0*(1-HR));   
    exp(-lam0 * t) * lt + c1 * exp(-HR * lam0 * t) * (1 - lt)
  }
  f.logHR = function(t){
    delay = dist$exp$delay; HR = dist$exp$HR
    if (dist$crossover$status == "N"){
      return(log(HR)*as.numeric(t >= delay))
    } else{
      HRx = dist$crossover$HRx; Tx = dist$crossover$Tx
      btw = as.numeric(t >= delay & t < Tx)
      ge = as.numeric(t >= Tx)
      return(log(HR) * btw + ge * log(HRx))
    }
  }
  
  # Construct accrual functions
  # FZ 05/07/2024
  # if the accrual duration A and accrual power xi are provided (xi=1 if not specified), then F.entry will be defined
  # if F.entry is provided instead A and xi, then use F.entry directly
  # if neither A (with xi) nor F.entry is defined, then warning message will be returned.
  if(!is.null(accr$A) & is.null(accr$F.entry)){
    if(!is.null(accr$xi)){
      A = accr$A; xi = accr$xi; 
    }else{
      warning("The accrual power parameter xi is not defined. The default value xi=1 will be used.")
      xi = 1
    }
    F.entry = function(t){(t/A)^xi*as.numeric(t <= A) + as.numeric(t > A)}
  }else if(is.null(accr$A) & !is.null(accr$F.entry)){
    F.entry = accr$F.entry
  }else if(is.null(accr$A) & is.null(accr$F.entry)){
    warning("A accrual list should be defined.")
  }else if(!is.null(accr$A) & !is.null(accr$F.entry)){
    warning("Both power law accrual format (A, xi) and customized accrual function (F.entry) are provided. 
             F.entry will be prioritized for use.")
    F.entry = accr$F.entry
  }
  
  if(is.null(accr$G.ltfu)){
    G.ltfu = function(t){0}
  }else{
    G.ltfu = accr$G.ltfu
  }
  
  alpha = alphabeta$alpha; side = alphabeta$side
  overall.alpha = alphabeta$overall.alpha; 

  
  #if alpha is not provided, use sf to derive alpha. 
  #if alpha is provided, then sf is ignored.
  if(is.null(alpha) && !is.null(overall.alpha)){
    ld.obf = function(s){
      if (side == 1){a = 2*(1 - pnorm(qnorm(1-overall.alpha/2)/sqrt(s)))}
      if (side == 2){a = 2*2*(1 - pnorm(qnorm(1-overall.alpha/4)/sqrt(s)))}
      return(a)
    }
    ld.pk = function(s){overall.alpha * log(1 + (exp(1)-1)*s)}
    ld.gamma<-function(s,param=-2){overall.alpha * (1-exp(-s*param))/(1-exp(-param))}
    #allocate alpha based on proportional of events, pseudo information
    nE = rep(NA, K)
    for (j in 1:K){
      nE[j] = f.nEvents(T = T[j], r = r, h0 = h0, S0 = S0, h1 = h1, S1 = S1, 
                        F.entry = F.entry, G.ltfu = G.ltfu, n = n)$n.events$n.events.total
    }
    timing = nE/nE[K]
    
    if (alphabeta$sf$type == "LDOF"){
      gs.alpha = ld.obf(s = timing)
    }
    if (alphabeta$sf$type == "LDPK") {
      gs.alpha = ld.pk(s = timing)
    }
    if (alphabeta$sf$type == "GAMMA") {
      gs.alpha = ld.gamma(s = timing,param=alphabeta$sf$param)
    }
    if (K == 1){alpha = overall.alpha} else{
      alpha[1] = gs.alpha[1]
      for(i in 2:K){alpha[i] = gs.alpha[i] - gs.alpha[i-1]}
    }
  }

  #Call Group sequential design power function
  gs.power = wlr.power.maxcombo(T = T, events = NULL, 
                 alpha = alpha, power = NULL, side = side, r = r, n = n, 
                 h0 = h0, S0=S0, h1 = h1, S1= S1, f.logHR = f.logHR, 
                 f.ws = f.ws, F.entry=F.entry, G.ltfu=G.ltfu,
                 show.setting=show.setting, non.centrality = non.centrality)
  
  setting = list()
  setting$dist = dist; setting$accr = accr; 
  setting$alphabeta = alphabeta;
  o = list()
  o$design = gs.power
  #o$setting = setting
  
  return(o)   
}

function_codes.plot_events:
plot_events = function(Tmax = 50, r=1, h0=h0, S0=S0, h1=h1, S1=S1, 
                F.entry = F.entry, G.ltfu = G.ltfu, n = 100, 
                leg=list(x=0, y=n/2,txt=c("Control", "Exp. Arm", "Total")), 
                param=list(xlab = "Calendar Time (mo)", 
                         ylab = "Cumulative Events",
                         main = "Cumulative Events")){
  t = seq(1, Tmax, by = 1)
  nE = matrix(NA, nrow = length(t), ncol=3)
  for (i in 1:length(t)) {
    o = f.nEvents(T = t[i], r = r, h0 = h0, S0 = S0, h1 = h1, S1 = S1, 
                  F.entry = F.entry, G.ltfu = G.ltfu, n = n);
    nE[i, 1] = o$n.events$n.events0; 
    nE[i, 2] = o$n.events$n.events1; 
    nE[i, 3] = o$n.events$n.events.total
  }

  plot(t, nE[, 3], type = "n", xlab=param$xlab, ylab=param$ylab, main=param$main) 
  lines(t, nE[, 1], lty = 1, col=1, lwd=3)
  lines(t, nE[, 2], lty = 2, col=2, lwd=3)
  lines(t, nE[, 3], lty = 3, col=3, lwd=3)
  abline(h = seq(0, max(nE), 25), col="gray80", lty=3)
  abline(v=seq(0, Tmax, by=2), col="gray80", lty=3)
  
  legend(0, max(nE[, 3]), leg$txt, col=1:3, lty=1:3, bty="n", cex=0.8)
  
}

function_codes.sim.pwexp:
sim.pwexp = function(nSim=100, N = 672, A = 21, w=1.5, r=1, lambda0=log(2)/11.7, lambda1=log(2)/11.7*0.745, cuts=NULL, dropOff0=0, dropOff1=0, targetEvents = c(397, 496)) {
  
  nEachMonth = f.nEachMonth(N=N, A=A, w=w, r=r)
  
  gamma = nEachMonth$n0 + nEachMonth$n1
  eta0 = -log(1-dropOff0)
  eta1 = -log(1-dropOff1)
  
  o = nphsim::nphsim(nsim=nSim,lambdaC=lambda0,lambdaE=lambda1, ssC=N/(r+1), ssE=N*r/(r+1),
             intervals=cuts, gamma=gamma, R=rep(1, A),eta=eta0, etaE=eta1,fixEnrollTime = FALSE)
  dat = o$simd
  data.out = NULL
  L = length(targetEvents) #number of analyses
  
  for (j in 1:nSim) {
    
    dataj = dat[dat$sim == j,]
    
    #rename variables
    dataj <- dplyr::rename(dataj, enterTime = enterT, calendarTime = ct, survTime= survival)

    #cut data according to the specified target events    
    dataj.cut <- lapply(1:L, function(k) {
      f.dataCut(data=dataj, targetEvents[k])
    })
    
    data.out=lapply(1:L, function(k) {
      rbind(data.out[[k]], dataj.cut[[k]])
    })
    
  }
  return(data.out)
}

function_codes.simulation.nphDesign:
simulation.nphDesign = function(nSim=10000, N = 672, A = 21, w=1.5, r=1, lambda0=log(2)/11.7, lambda1=log(2)/11.7*0.745, 
    cuts=NULL, dropOff0=0, dropOff1=0, targetEvents = c(290, 397, 496), 
    sf = "LDOF", overall.alpha = 0.025, side = 1, alpha = NULL,
    logrank="N", fws.options=NULL, H0 = "N", nphDesign = NULL, 
    save.data=F, parallelization=F, n.cores = 10) {

  ### create a big list saving simulated data
  sim.data<-vector("list",length=nSim)

  ##############
  #Extract the setting parameters from nphDesign object if provided
  ##############
  if(!is.null(nphDesign)){
    nph = f.extract(nphDesign)
    N = nph$N; A=nph$A;  w=nph$w; r=nph$r; lambda0=nph$lam0; lambda1 = nph$lam1;
    cuts = nph$cuts; targetEvents = ceiling(nph$targetEvents); overall.alpha = nph$overall.alpha;
    side = nph$side; alpha = nph$alpha;
    if(is.null(fws.options)){fws.options = list(nph$fws)}
  }

  #Simulation for checking type I error
  if (H0 == "Y"){lambda1 = lambda0} 

  ##############################
  #M Options of test strategies
  M = length(fws.options)

  #K analyses
  K=length(fws.options[[1]])

  timing = targetEvents / targetEvents[K]

  #if alpha is not provided, use sf to derive alpha. 
  #if alpha is provided, then sf is ignored.
  if(is.null(alpha) && !is.null(overall.alpha)){
    ld.obf = function(s){
      if (side == 1){a = 2*(1 - pnorm(qnorm(1-overall.alpha/2)/sqrt(s)))}
      if (side == 2){a = 2*2*(1 - pnorm(qnorm(1-overall.alpha/4)/sqrt(s)))}
      return(a)
    }
    ld.pk = function(s){overall.alpha * log(1 + (exp(1)-1)*s)}

    # https://rdrr.io/rforge/gsDesign/src/R/gsSpending.R LDPK added based on the reference code
    if (sf == "LDOF"){
      gs.alpha = ld.obf(s = timing)
    }
    if (sf == "LDPK") {
      gs.alpha = ld.pk(s = timing)
    }
    if (K == 1){alpha = overall.alpha} else{
      alpha[1] = gs.alpha[1]
      for(i in 2:K){alpha[i] = gs.alpha[i] - gs.alpha[i-1]}
    }
  }

  wlr.sim = array(NA, dim=c(nSim, M, K, 5))
  if (logrank == "Y") {lr.sim = array(NA, dim=c(nSim, K, 5))}

  if(parallelization){
    ##############
    #Run wlr test in parallel
    ##############
    library(parallel)   #For PSOCK parallel backend
    library(foreach)    #For 'foreach' loop
    library(doParallel) #For using PSOCK cluster with operator '%dopar%'
    n.cores <- n.cores
    my.cluster <- makeCluster(
      n.cores, 
      type = "PSOCK"
    )
    clusterEvalQ(my.cluster, .libPaths(.libPaths())
    )
    registerDoParallel(cl = my.cluster)
    clusterEvalQ(my.cluster, library(nphDesign))
    for (i in 1:nSim) {
      #(1). Generate data
      dati = sim.pwexp(nSim=1, N = N, A = A, w=w, r=r, lambda0=lambda0, lambda1=lambda1, 
                       cuts=cuts, dropOff0=dropOff0, dropOff1=dropOff1, targetEvents = targetEvents)
      #(2). Add group variable
      for (j in 1:K) {
        dati[[j]]$group = as.numeric(dati[[j]]$treatment == "experimental")
      }  
      sim.data[[i]]<-dati
    }

    #(3). Testing strategy m
    for (m in 1:M){    
      #Perform weighted log-rank test for each analysis in strategy m
      ## This next line takes a long-time to compute, making simulation difficult. Use parallel computing instead
      wlr <- foreach(i = 1:nSim) %dopar% {
        wlr.inference(datasets=sim.data[[i]], alpha = alpha, side = side, f.ws=fws.options[[m]])$test.results
      }
      stopCluster(cl = my.cluster) ## Stop cluster
      for (i in 1:nSim) {
        wlri = wlr[[i]][!duplicated(wlr[[i]]$analysis),]
        wlri$result = as.numeric(wlri$inference=="Positive")
        wlr.sim[i, m, , ] = as.matrix(wlri[,c(2,3,5,6,8)])
      }
    }

    for (i in 1:nSim) {
      #(4). Standard log-rank test for all analyses if requested
      if (logrank=="Y"){
        if(K > 1){
          #GSD boundary for each analysis
          if(side == 1) {
            z.bd <- gsDesign::gsDesign(k=K,  alpha=overall.alpha,timing=timing[1:(K-1)], 
                                       sfu=gsDesign::sfLDOF)$upper$bound 
          } else{
            z.bd <- gsDesign::gsDesign(k=K,  alpha=overall.alpha/2,timing=timing[1:(K-1)], 
                                       sfu=gsDesign::sfLDOF)$upper$bound 
          }
        } else {
          if(side == 1) {z.bd = qnorm(1-overall.alpha)} else{z.bd = qnorm(1-overall.alpha/2)}
        }
        for (j in 1:K){
          lr.test = survival::survdiff(survival::Surv(survTimeCut, 1-cnsrCut) ~ group, data = sim.data[[i]][[j]])

          #convert to z value in correct direction: z>0 means better experimental arm.
          better = as.numeric(lr.test$obs[1] > lr.test$obs[2])
          sign = 2*better - 1
          z = sqrt(lr.test$chisq) * sign

          #count power
          lr.sim[i, j, 1] = z
          if (side == 1){ p = 1 - pnorm(z)} else {p = 2*(1 - pnorm(z))}

          lr.sim[i, j, 2] = p
          lr.sim[i, j, 3] = j
          lr.sim[i, j, 4] = z.bd[j]
          lr.sim[i, j, 5] = as.numeric(z > z.bd[j])
        }
      }
    }

  }else{
    for (i in 1:nSim) {
      #(1). Generate data
      dati = sim.pwexp(nSim=1, N = N, A = A, w=w, r=r, lambda0=lambda0, lambda1=lambda1, 
                       cuts=cuts, dropOff0=dropOff0, dropOff1=dropOff1, targetEvents = targetEvents)
      #(2). Add group variable
      for (j in 1:K) {
        dati[[j]]$group = as.numeric(dati[[j]]$treatment == "experimental")
      }  

      if(save.data){
        sim.data[[i]]<-dati
      }

      #(3). Testing strategy m
      for (m in 1:M){    
        #Perform weighted log-rank test for each analysis in strategy m
        wlri = wlr.inference(datasets=dati, alpha = alpha, side = side, f.ws=fws.options[[m]])$test.results
        wlri = wlri[!duplicated(wlri$analysis),]
        wlri$result = as.numeric(wlri$inference=="Positive")
        wlr.sim[i, m, , ] = as.matrix(wlri[,c(2,3,5,6,8)])
      }

      #(4). Standard log-rank test for all analyses if requested
      if (logrank=="Y"){
        if(K > 1){
          #GSD boundary for each analysis
          if(side == 1) {
            z.bd <- gsDesign::gsDesign(k=K,  alpha=overall.alpha,timing=timing[1:(K-1)], 
                                       sfu=gsDesign::sfLDOF)$upper$bound 
          } else{
            z.bd <- gsDesign::gsDesign(k=K,  alpha=overall.alpha/2,timing=timing[1:(K-1)], 
                                       sfu=gsDesign::sfLDOF)$upper$bound 
          }
        } else {
          if(side == 1) {z.bd = qnorm(1-overall.alpha)} else{z.bd = qnorm(1-overall.alpha/2)}
        }
        for (j in 1:K){
          lr.test = survival::survdiff(survival::Surv(survTimeCut, 1-cnsrCut) ~ group, data = dati[[j]])

          #convert to z value in correct direction: z>0 means better experimental arm.
          better = as.numeric(lr.test$obs[1] > lr.test$obs[2])
          sign = 2*better - 1
          z = sqrt(lr.test$chisq) * sign

          #count power
          lr.sim[i, j, 1] = z
          if (side == 1){ p = 1 - pnorm(z)} else {p = 2*(1 - pnorm(z))}

          lr.sim[i, j, 2] = p
          lr.sim[i, j, 3] = j
          lr.sim[i, j, 4] = z.bd[j]
          lr.sim[i, j, 5] = as.numeric(z > z.bd[j])
        }
      }
    }
  }

  pow = matrix(NA, nrow=M, ncol=K)
  overall.pow = rep(0, M)

  for(m in 1:M){for(j in 1:K){pow[m, j] = sum(wlr.sim[,m,j,5])/nSim}}
  for(m in 1:M){for(i in 1:nSim){
    overall.pow[m] =  overall.pow[m] + as.numeric(sum(wlr.sim[i,m,,5])>0)
  }}
  overall.pow = overall.pow / nSim

  o=list()
  o$power = pow; o$overall.power = overall.pow
  o$wlr.simulations = wlr.sim
  if(logrank=="Y"){
    lr.pow = rep(NA, K)
    for (j in 1:K) {lr.pow[j] = sum(lr.sim[,j,5])/nSim}

    lr.overall.pow = 0
    for (i in 1:nSim){lr.overall.pow = lr.overall.pow + as.numeric(sum(lr.sim[i,,5])>0)}
    lr.overall.pow = lr.overall.pow / nSim

    o$lr.overall.power = lr.overall.pow
    o$lr.power = lr.pow
    o$lr.simulations = lr.sim
  }
  if(save.data){
    o$sim.data = sim.data
  }
  return(o)
}

function_codes.summarize.nphDesign:
summarize.nphDesign = function(nphDesign = PFS.design, endpoint="Endpoint", caption="Summary of Statistical Design"){
  nph = f.extract(nphDesign)
  n = nph$N; A=nph$A;  w=nph$w; r=nph$r; 
  lambda0=nph$lam0; lambda1 = nph$lam1;
  cuts = nph$cuts; targetEvents = nph$targetEvents; 
  DCO = nph$DCO
  maturity = nph$maturity
  CV.HR = nph$CV.HR; CV.med = nph$CV.med
  b = nph$b
  
  overall.alpha = nph$overall.alpha;
  overall.power = nph$overall.power
  power = nph$power
  m0 = nph$m0; m1 = nph$m1
  
  #delayed effect
  if(!is.null(nph$cuts)) {delay = cuts[1]; AHR = nph$AHR; HR = NULL} else{
    #Prop. Hazards
    delay = NULL; HR = nph$AHR[1]; AHR = NULL
  }
  if(!is.null(nph$cuts)){delay = cuts[1]}
  
  #Ignore delayed effect in display
  delay = NULL
  side = nph$side; alpha = nph$alpha; f.ws = nph$fws
  
  #Number of analyses
  K = length(f.ws)
  J = lengths(f.ws) 
  timing = targetEvents/targetEvents[K]
  
  row.endpoint = c("Endpoint", endpoint)
  row.n = c("N", n)
  row.r = c("Randomization Ratio", paste(r, ": 1"))
  row.A = c("Accrual", paste(A, "months"))
  row.overall.alpha = c("Overall Alpha", 
                        paste(round(overall.alpha,4), "(", side, " sided)", sep=""))
  row.overall.power = c("Overall Power", paste(round(overall.power*100,1), "%", sep=""))  
  row.median = c("Median (Control vs. Exp. Arm)", 
                 paste(round(m0,1), "vs", round(m1,1)))
  
  
  if(!is.null(delay)){
    row.delay = c("Delayed Effect", delay)
    row.target.HR = NULL
  }else{
    row.delay = NULL
    row.target.HR = c("Target HR", HR)
  }
  
  #dataframe for overall study setting
  tab = data.frame(
    rbind(
      row.endpoint, 
      row.n,
      row.r,
      row.A,
      row.overall.alpha,
      row.overall.power,
      row.median,
      row.delay,
      row.target.HR
    )
  )
  
  if(K > 1) {tab$Analysis = ""}
  
  #summary of study design per analysis
  if(K > 1){
    #group sequential design
    for (i in 1:K){
      row.DCO = c("Expected Time of Analysis", round(DCO[i], 1))
      row.IF = c("Information Fraction", round(timing[i],2))
      row.events = c("Target Events (% maturity) for Analysis",
                     paste(round(targetEvents[i]), 
                           "(", round(maturity$overall.maturity[i]*100,1), "%)", sep=""))
      
      if(!is.null(AHR)){row.AHR = c("Expected Average HR", 
                                    round(AHR[i], 3))}else{row.AHR=NULL}
      
      if(!is.null(CV.HR)){
        med.imp = CV.med[i] - m0
        CV.HR.med = paste(round(CV.HR[i], 3), "(", 
                          round(med.imp, 1), ")", sep="")
        row.CV = c("Critical Value in HR (median imp.)", CV.HR.med)
      } else {row.CV = NULL}
      
      #alpha and power
      if(side == 1) {
        row.alpha = c("p value bound (alpha)", round(1-pnorm(b[i]), 4))
      }else{
        row.alpha = c("p value bound (alpha)", round(2*(1-pnorm(b[i])), 4))
      }
      if (round(power[i]*100, 1)==100){power.txt = "> 99%"}else{
        power.txt = paste(round(power[i]*100, 1), "%", sep="")
      }
      row.power = c("Power", power.txt)
      
      tabi = data.frame(rbind(
        row.DCO,
        row.IF,
        row.events,
        row.AHR,
        row.CV,
        row.alpha,
        row.power
      ))
      if(K == 2 && i == 1){tabi$Analysis = "Interim Analysis"}
      if(K == 2 && i == 2){tabi$Analysis = "Final Analysis"}
      if(K > 2 && i < K){tabi$Analysis = paste("Interim Analysis", i)}
      if(K > 2 && i == K){tabi$Analysis = "Final Analysis"}
      
      tab = rbind(tab, tabi)
    }
  } else{
    #Only 1 analysis
    row.DCO = c("Expected Time of Analysis", round(DCO, 1))
    row.events = c("Number of Target Events (% maturity) for Analysis",
                   paste(round(targetEvents), 
                         "(", round(maturity$overall.maturity*100,1), "%)", sep=""))
    if(!is.null(CV.HR)){
      med.imp = CV.med - m0
      CV.HR.med = paste(round(CV.HR, 3), "(", 
                        round(med.imp, 1), ")", sep="")
      row.CV = c("Critical Value in HR (median imp.)", CV.HR.med)
    } else {row.CV = NULL}
    
    #alpha and power
    if(side == 1) {
      row.alpha = c("p value bound (alpha)", round(1-pnorm(b), 4))
    }else{
      row.alpha = c("p value bound (alpha)", round(2*(1-pnorm(b)), 4))
    }
    if (round(power*100, 1)==100){power.txt = "> 99%"} else{
      power.txt = paste(round(power*100, 1), "%", sep="")
    }
    row.power = c("Power", power.txt)
    
    tabi = data.frame(rbind(
      row.DCO,
      row.events,
      row.CV,
      row.alpha,
      row.power
    ))
    tab = rbind(tab, tabi)
  } 
  tab = dplyr::rename(tab, Description = X1, Design = X2)
  
  if(K > 1){    
    out = tab %>% group_by(Analysis) %>% gt()
  } else{
    out = tab %>% gt()
  }
  
  out = out %>% tab_header(
    title = md(caption), 
  ) %>% tab_source_note(
    source_note = md("Time unit is month.")
  )
  return(out)
}

function_codes.f.w:
f.w = function(t, f.S = S0, f.ws=f.ws, tau=tau, s.tau=s.tau, rho=rho, gamma=gamma){
    s = f.S(t)
    #First priority: f.ws
    if(!is.null(f.ws)){
      w = f.ws(s)
    }else {
      #Second priority: s.tau
      if (!is.null(s.tau)){
        s.til = apply(cbind(s, s.tau), MARGIN=1,FUN=max);
      } else {
        s.til = apply(cbind(s, f.S(tau)), MARGIN=1,FUN=max);        
      }
      w = s.til^rho*(1-s.til)^gamma
    }
    return(w)
  }

function_codes.I.eta:
I.eta = function(t){
    w = f.w(t, f.S = S.bar, f.ws=f.ws, tau=tau, s.tau=s.tau, rho=rho, gamma=gamma)
    return(w * f.logHR(t)*F.entry(T-t) * (1 - G.ltfu(t)) * f.bar(t))
  }

function_codes.I.d:
I.d = function(t){
      w = f.w(t, f.S = S.bar, f.ws=f.ws[[i]], tau=tau[i], s.tau=s.tau[i], rho=rho[i], gamma=gamma[i])
      return(w * F.entry(T[i]-t) * (1 - G.ltfu(t)) * f.bar(t))
    }

function_codes.I.KP1:
I.KP1 = function(t){
    w = f.w(t, f.S = S.bar, f.ws=f.ws, tau=tau, s.tau=s.tau, rho=rho, gamma=gamma)
    HRt = exp(f.logHR(t))
    return(w *HRt/(1 + HRt)*F.entry(T-t) * (1 - G.ltfu(t)) * f.bar(t))
  }

function_codes.I.KP2:
I.KP2 = function(t){
    w = f.w(t, f.S = S.bar, f.ws=f.ws, tau=tau, s.tau=s.tau, rho=rho, gamma=gamma)
    HRt = exp(f.logHR(t))
    return(w *1/(1 + HRt)*F.entry(T-t) * (1 - G.ltfu(t)) * f.bar(t))
  }

function_codes.I.I0:
I.I0 = function(t){
      w = f.w(t, f.S = S.bar, f.ws=f.ws[[i]], tau=tau[i], s.tau=s.tau[i], rho=rho[i], gamma=gamma[i])
      return(w^2 * F.entry(T[i]-t) * (1 - G.ltfu(t)) * f.bar(t))
    }

function_codes.I.d0:
I.d0 = function(t){
    w = f.w(t, f.S = S.bar, f.ws=f.ws, tau=tau, s.tau=s.tau, rho=rho, gamma=gamma)
    return(w * (exp(f.logHR(t))-1)*F.entry(T-t) * (1 - G.ltfu(t)) * f0(t))
  }

function_codes.I.d1:
I.d1 = function(t){
    w = f.w(t, f.S = S.bar, f.ws=f.ws, tau=tau, s.tau=s.tau, rho=rho, gamma=gamma)
    return(w * (1-exp(-f.logHR(t)))*F.entry(T-t) * (1 - G.ltfu(t)) * f1(t))
  }

function_codes.wlr:
wlr = function(time=c(5,7,10,12,12,15,20,20), event=c(1,0,0,1,1,0,1,1),
               group=c(0,1,0,1,0,1,0,1), strata1=NULL, strata2=NULL, strata3=NULL, 
               rho=0, gamma=1, tau = NULL, s.tau=0.5,
               f.ws=NULL, side = c("two.sided", "one.sided")) {
  #Initialize strata1-3
  n = length(time)
  if(is.null(strata1)){strata1 = rep(1,n)}
  if(is.null(strata2)){strata2 = rep(1,n)}
  if(is.null(strata3)){strata3 = rep(1,n)}
  u.strata1 = unique(strata1)
  u.strata2 = unique(strata2)
  u.strata3 = unique(strata3)
  
  n.strata1 = length(u.strata1)
  n.strata2 = length(u.strata2)
  n.strata3 = length(u.strata3)
  n.strata = n.strata1*n.strata2*n.strata3
  
  #unstratified analysis
  if (n.strata == 1) {
    o = wlr0(time=time, event=event, group=group, rho=rho, gamma=gamma, tau = tau, 
             s.tau=s.tau, f.ws=f.ws, side = side)
  }else{
    uni.event.time=data=test.results.strata=NULL
    for (i in 1:n.strata1) {
      for (j in 1:n.strata2){
        for (k in 1:n.strata3){
          ix = (strata1==u.strata1[i] & strata2 == u.strata2[j] & strata3 == u.strata3[k])
          #ignore empty strata
          if(sum(ix) > 0){
            timei = time[ix]
            eventi = event[ix]
            groupi = group[ix]
           
            wlr.i = wlr0(time=timei, event=eventi, group=groupi, rho=rho, gamma=gamma, tau = tau, 
                     s.tau=s.tau, f.ws=f.ws, side = side)
          
            wlr.i$uni.event.time$strata1 = u.strata1[i]
            wlr.i$uni.event.time$strata2 = u.strata2[j]
            wlr.i$uni.event.time$strata3 = u.strata3[k]
            uni.event.time = rbind(uni.event.time, wlr.i$uni.event.time)
          
            wlr.i$data$strata1 = u.strata1[i];
            wlr.i$data$strata2 = u.strata2[j]
            wlr.i$data$strata3 = u.strata3[k]
            data = rbind(data, wlr.i$data);
          
            wlr.i$test.results$strata1 = u.strata1[i]
            wlr.i$test.results$strata2 = u.strata2[j]
            wlr.i$test.results$strata3 = u.strata3[k]
            test.results.strata = rbind(test.results.strata, wlr.i$test.results)
          }  
        } 
      }       
    }  
    
    U=uni.event.time$U
    V=uni.event.time$V
    z=sum(U[!is.nan(V)])/sqrt(sum(V[!is.nan(V)]))
    
    if(side[1] == "one.sided") {
      test.side = 1; p = 1-pnorm(z)
      } else {
        test.side = 2
        p = 2*(1-pnorm(abs(z)))
      }
    
    #create a dataframe to output the parameters
    #chisq = z*z; 
    test.results = data.frame(cbind(z, p, test.side))
    
    o=list()
    
    o$uni.event.time = uni.event.time
    #o$data = data
    
    o$test.results.strata = test.results.strata
    o$test.results = test.results

    if(!is.null(f.ws)){wt = f.ws} else{
      wt = data.frame(cbind(rho, gamma, tau, s.tau))
    }
    o$wt = wt
  }
  return(o)
}

function_codes.f.solver.b:
f.solver.b = function(corr = corr){
   b = rep(NA, K)
   if (side == 1) {b[1] = qnorm(1-alpha[1])} else {b[1] = qnorm(1-alpha[1]/2)}
  
   if(K > 1){
    if(side == 1){
      for (i in 2:K){
        f.b = function(x){
          mvtnorm::pmvnorm(lower = c(rep(-Inf, i-1), x), 
                           upper = c(b[1:(i-1)], Inf), mean=rep(0, i), 
                           corr = corr[1:i, 1:i], abseps = 1e-8, maxpts=100000)[1] - alpha[i]
        }
        b[i] = uniroot(f=f.b, interval=c(1, 20), tol = 1e-8)$root
      }
    } else {
      for (i in 2:K){
        f.b = function(x){
          I1 = mvtnorm::pmvnorm(lower = c(-b[1:(i-1)], x), upper = c(b[1:(i-1)], Inf), mean=rep(0, i), corr = corr[1:i, 1:i], abseps = 1e-8, maxpts=100000)[1]
          I2 = mvtnorm::pmvnorm(lower = c(-b[1:(i-1)], -Inf), upper = c(b[1:(i-1)], -x), mean=rep(0, i), corr = corr[1:i, 1:i], abseps = 1e-8, maxpts=100000)[1]
          return(I1+I2-alpha[i])
        }
        b[i] = uniroot(f=f.b, lower=1, upper=20, tol = 1e-8)$root
      }
    }  
   }  
   return(b)
  }

function_codes.f.b:
f.b = function(x){
          LL1 = rep(-Inf, sum(J[1:(i-1)]))
          UU1 = rep(b[1], J[1])
          if(i > 2){for (j in 2:(i-1)){UU1 = c(UU1, rep(b[j], J[j]))}}
          
          idx1 = 1:sum(J[1:(i-1)])
          if (length(LL1) == 1) {
            P1 = pnorm(UU1)
          } else {
            P1 = mvtnorm::pmvnorm(lower = LL1, upper = UU1, mean=rep(0, length(idx1)), 
                                  corr = corr[idx1, idx1], abseps = 1e-8, maxpts=100000)[1]
          }
          
          LL2 = rep(-Inf, sum(J[1:i]))
          UU2 = c(UU1, rep(x, J[i]))
          
          idx = 1:sum(J[1:i]) #index of the corr matrix
          P2 = mvtnorm::pmvnorm(lower = LL2, upper = UU2, mean=rep(0, length(idx)), 
                                corr = corr[idx, idx], abseps = 1e-8, maxpts=100000)[1]
          return(P1 - P2 - alpha[i])
        }

function_codes.wlr.cov:
wlr.cov = function(time=c(5,7,10,12,12,15,20,20), event=c(1,0,0,1,1,0,1,1),
                   group=c(0,1,0,1,0,1,0,1), strata1=NULL, strata2=NULL, strata3=NULL, 
                   rho1=0, gamma1=0, tau1 = NULL, s.tau1=0.5,
                   rho2=0, gamma2=1, tau2 = NULL, s.tau2=0.5,
                   f.ws1=NULL, f.ws2=NULL) {
  
  #Initialize strata1-3
  n = length(time)
  if(is.null(strata1)){strata1 = rep(1,n)}
  if(is.null(strata2)){strata2 = rep(1,n)}
  if(is.null(strata3)){strata3 = rep(1,n)}
  u.strata1 = unique(strata1)
  u.strata2 = unique(strata2)
  u.strata3 = unique(strata3)
  
  n.strata1 = length(u.strata1)
  n.strata2 = length(u.strata2)
  n.strata3 = length(u.strata3)
  n.strata = n.strata1*n.strata2*n.strata3
  
  #unstratified analysis
  if (n.strata == 1) {
    o = wlr.cov0(time=time, event=event, group=group, rho1=rho1, gamma1=gamma1, tau1 = tau1, 
                 s.tau1=s.tau1, rho2=rho2, gamma2=gamma2, tau2 = tau2, 
                 s.tau2=s.tau2,f.ws1=f.ws1,f.ws2=f.ws2)
  }else{
    uni.event.time=data=NULL; cov=0
    for (i in 1:n.strata1) {
      for (j in 1:n.strata2){
        for (k in 1:n.strata3){
          ix = (strata1==u.strata1[i] & strata2 == u.strata2[j] & strata3 == u.strata3[k])
          if(sum(ix) > 0){
            timei = time[ix]
            eventi = event[ix]
            groupi = group[ix]
          
            wlr.i = wlr.cov0(time=timei, event=eventi, group=groupi, rho1=rho1, gamma1=gamma1, tau1 = tau1, 
                           s.tau1=s.tau1, rho2=rho2, gamma2=gamma2, tau2 = tau2, 
                           s.tau2=s.tau2,f.ws1=f.ws1,f.ws2=f.ws2)
          
            wlr.i$uni.event.time$strata1 = u.strata1[i]
            wlr.i$uni.event.time$strata2 = u.strata2[j]
            wlr.i$uni.event.time$strata3 = u.strata3[k]
            uni.event.time = rbind(uni.event.time, wlr.i$uni.event.time)
          
            wlr.i$data$strata1 = u.strata1[i];
            wlr.i$data$strata2 = u.strata2[j]
            wlr.i$data$strata3 = u.strata3[k]
            data = rbind(data, wlr.i$data);
          
            cov = cov + wlr.i$cov
          }
        }  
      }       
    }  
    corr = cov[1,2]/(sqrt(cov[1,1]*cov[2,2]))    
    o=list()
    o$uni.event.time = uni.event.time
    #o$data = data
    o$cov = cov
    o$corr = corr
    if(!is.null(f.ws1)){wt1 = f.ws1} else{
      wt1 = data.frame(cbind(rho1, gamma1, tau1, s.tau1))
    }
    if(!is.null(f.ws2)){wt2 = f.ws2} else{
      wt2 = data.frame(cbind(rho2, gamma2, tau2, s.tau2))
    }
    o$wt1 = wt1
    o$wt2 = wt2    
  }
  return(o)
}

function_codes.wlr.cov0:
wlr.cov0 = function(time=c(5,7,10,12,12,15,20,20), event=c(1,0,0,1,1,0,1,1),
                    group=c(0,1,0,1,0,1,0,1), rho1=0, gamma1=0, tau1 = NULL, s.tau1=0.5,
                    rho2=0, gamma2=1, tau2 = NULL, s.tau2=0.5,
                    f.ws1=NULL, f.ws2=NULL) {

  u.eTime = unique(time[event==1]) #vector of unique event times
  u.Ne = length(u.eTime) #number of unique event times
  if (u.Ne == 0) {return(NULL); stop("No events")}
  
  u.eTime = sort(u.eTime) #sort by increasing order of unique event times
  
  Y0 = Y1 = Y = dN = dN0 = dN1 = rep(NA, u.Ne) #risk-set, death-set
  
  for (i in 1:u.Ne) {
    Y0[i] = sum(time>=u.eTime[i] & group == 0)
    Y1[i] = sum(time>=u.eTime[i] & group == 1)
    dN0[i] = sum(time == u.eTime[i] & group == 0)
    dN1[i] = sum(time == u.eTime[i] & group == 1)
  }
  
  Y=Y0+Y1
  dN = dN0 + dN1
  
  s = rep(NA, u.Ne)
  
  s[1] = 1 - dN[1]/Y[1]
  if (u.Ne > 1) {
    for (i in 2:u.Ne) {
      s[i] = s[i-1] * (1 - dN[i]/Y[i])
    }
  }
  
  f.w = function(s=s, f.ws=f.ws1, tau=tau1, s.tau=s.tau1, rho=rho1, gamma=gamma1) {
    w = rep(NA, u.Ne)
    #If f.ws() function is provided, then use directly. 
    if(!is.null(f.ws)){
        w[1] = f.ws(1)
      for(i in 2:u.Ne){
        w[i] = f.ws(s[i-1])
        s.til=NULL
      }
    } else {
      #Find S(tau): = S(max(ti)|ti <= tau), where ti is unique event time.
      if (is.null(s.tau)) {
        if (is.null(tau)){stop("tau or s.tau or f.ws is required for weight function.")}else{
          s.tau = 1
          for (i in 1:u.Ne) {
            if (u.eTime[i] <= tau) {s.tau = s[i]} else {break}
          }
        }
      } #if s.tau is missing, find s.tau by tau.
      s.til = apply(cbind(s, s.tau),MARGIN=1,FUN=max)
      
      if(gamma == 0){w[1] = 1} else{w[1] = 0}; 
      for (i in 2:u.Ne){ w[i] = s.til[i-1]^rho*(1-s.til[i-1])^gamma }
      #w = s.til^rho*(1-s.til)^gamma
    }
    ot = list()
    ot$w = w; ot$s.til = s.til
    return(ot)
  }
  ow1 = f.w(s=s, f.ws=f.ws1, tau=tau1, s.tau=s.tau1, rho=rho1, gamma=gamma1)
  ow2 = f.w(s=s, f.ws=f.ws2, tau=tau2, s.tau=s.tau2, rho=rho2, gamma=gamma2)
  w1 = ow1$w; s.til1 = ow1$s.til
  w2 = ow2$w; s.til2 = ow2$s.til
  
  V = matrix(NA, nrow=2, ncol=2)  
  v11 = w1*w1*Y0*Y1/(Y^2)*(Y-dN)/(Y-1)*dN
  v12 = w1*w2*Y0*Y1/(Y^2)*(Y-dN)/(Y-1)*dN
  v22 = w2*w2*Y0*Y1/(Y^2)*(Y-dN)/(Y-1)*dN
  
  V[1,1]= sum(v11[!is.nan(v11)])
  V[1,2]=V[2,1]=sum(v12[!is.nan(v12)])
  V[2,2]=sum(v22[!is.nan(v22)])
  
  corr = V[1,2]/(sqrt(V[1,1]*V[2,2]))
  
  #create a dataframe to output the list of unique event times and statistics
  uni.event.time = data.frame(cbind(u.eTime,Y0, Y1, Y, dN0, dN1, dN, s, s.til1, s.til2, w1, w2, v11, v12, v22))
  
  #create a dataframe to output the original data
  data = data.frame(cbind(time, event, group))
  
  o=list()
  o$uni.event.time = uni.event.time
  #o$data = data
  o$corr = corr
  o$cov = V
  
  if(!is.null(f.ws1)){wt1 = f.ws1} else{
    wt1 = data.frame(cbind(rho1, gamma1, tau1, s.tau1))
  }
  if(!is.null(f.ws2)){wt2 = f.ws2} else{
    wt2 = data.frame(cbind(rho2, gamma2, tau2, s.tau2))
  }
  o$wt1 = wt1
  o$wt2 = wt2   
  return(o)
}

function_codes.wlr.inference:
wlr.inference = function(datasets=list(IA1=data1, IA2=data2, FA=data3), 
        alpha = c(0.01, 0.02, 0.02)/2, side = 1, 
        strata1 = NULL, strata2 = NULL, strata3 = NULL,
        f.ws=list(IA1=list(lr), IA2=list(lr, fh01), FA=list(lr, fh01, fh11))){

  #K analyses
  K=length(f.ws)
  
  #Number of test components in each analysis
  J = lengths(f.ws)
  
  #Find the complete correlation matrix among all weighted log-rank 
  #tests J[1]+J[2]+...+J[K] dimensions
  
  corr = matrix(1, nrow=sum(J), ncol=sum(J))
  #calculate the correlation between Zij and Z_i'j'
  for (i in 1:K){
    for (j in 1:J[i]){
      for (ip in i:K){
        for (jp in 1:J[ip]){
          row = as.numeric(i>=2)*sum(J[1:(i-1)])+j #row location of the corr matrix
          
          #incremental location pointer for column compared to row of the corr matrix
          incr = (as.numeric(ip>=2)*sum(J[1:(ip-1)])+jp)-(as.numeric(i>=2)*sum(J[1:(i-1)])+j)
          col = row + incr
          #incr controls the computation only limited to upper right corner
          if(incr > 0){
            #information matrix for Zij and Zi'j'
            datai = datasets[[i]]; dataip = datasets[[ip]]

            corr[row, col] = wlr.cov2t(time1=datai$survTimeCut, event1=1-datai$cnsrCut, 
                            time2=dataip$survTimeCut, event2=1-dataip$cnsrCut, 
                            group=datai$group, 
                            strata1=strata1, strata2=strata2, strata3=strata3,
                            f.ws1=f.ws[[i]][[j]], f.ws2=f.ws[[ip]][[jp]])$corr
            corr[col, row] = corr[row, col]
          }
        }
      }
    }
  }
  
  #Rejection boundary: recursively solve for the rejection boundary for each analysis
  b = rep(NA, K)
  
  #First Analysis
  #maxcombo has at least 2 components.
  if (J[1] >= 2){
    if(side == 1){
      #1-sided test
      f.b = function(x){
        1-mvtnorm::pmvnorm(lower=rep(-Inf,J[1]),upper=rep(x, J[1]), 
            mean=rep(0, J[1]), corr = corr[1:J[1],1:J[1]], abseps = 1e-8, maxpts=100000)[1] - alpha[1]
      }
      b[1] = uniroot(f=f.b, interval=c(1, 20), tol = 1e-8)$root
    } 
  } else{
    if (side == 1) {b[1] = qnorm(1-alpha[1])} else {b[1] = qnorm(1-alpha[1]/2)}
  }
  
  #Recursively solve other boundaries from 2nd analysis to Kth analysis
  if(K > 1){
    for(i in 2:K){
      if(side == 1){
        #1-sided test
        f.b = function(x){
          LL1 = rep(-Inf, sum(J[1:(i-1)]))
          UU1 = rep(b[1], J[1])
          if(i > 2){for (j in 2:(i-1)){UU1 = c(UU1, rep(b[j], J[j]))}}
          
          idx1 = 1:sum(J[1:(i-1)])
          if (length(LL1) == 1) {
            P1 = pnorm(UU1)
          } else {
            P1 = mvtnorm::pmvnorm(lower = LL1, upper = UU1, mean=rep(0, length(idx1)), 
                                  corr = corr[idx1, idx1], abseps = 1e-8, maxpts=100000)[1]
          }
          
          LL2 = rep(-Inf, sum(J[1:i]))
          UU2 = c(UU1, rep(x, J[i]))
          
          idx = 1:sum(J[1:i]) #index of the corr matrix
          P2 = mvtnorm::pmvnorm(lower = LL2, upper = UU2, mean=rep(0, length(idx)), 
                                corr = corr[idx, idx], abseps = 1e-8, maxpts=100000)[1]
          return(P1 - P2 - alpha[i])
        }
        b[i] = uniroot(f=f.b, interval=c(1, 20), tol = 1e-8)$root
      }
    }
  }
  
  #Calculate p value for each analysis
  test.results = NULL
  for (i in 1:K){
    if(side == 1){
      testi = wlr.maxcombo(time=datasets[[i]]$survTimeCut, event=1-datasets[[i]]$cnsrCut,
              group=datasets[[i]]$group, 
              strata1=strata1, strata2=strata2, strata3=strata3, 
              rho = NULL, gamma=NULL, tau = NULL, s.tau=NULL,
              f.ws=f.ws[[i]], side = "one.sided")$test.results
      testi$analysis = i; testi$z.bound = b[i]; 
      
      testi$inference = ifelse(testi$z.max > b[i], "Positive", "Negative")
      test.results = rbind(test.results, testi)
    }
  }
  
  o = list()
  o$corr = corr
  o$test.results = test.results 
  o$wt = f.ws
  setting = list(alpha=alpha, side=side)
  o$setting = setting
  return(o)
}

function_codes.f.cov:
f.cov = function(f = f0, f.S = S0) {
   #(1) Only 1 analysis time
   if(length(T)==1 || (length(T)==2 && T[2] == T[1])){
  
    #(1.1) Only 1 weighted log-rank test at 1 time
    if(is.null(f.ws[[2]]) && (length(rho)==1 || is.null(rho))) {
      I11 = function(t){
        w1 = f.w(t, f.S = f.S, f.ws0=f.ws[[1]], tau0=tau[1], s.tau0=s.tau[1], rho0=rho[1], gamma0=gamma[1])
        return(w1^2 * F.entry(T[1]-t) * (1 - G.ltfu(t)) * f(t))
      }
      sigma11 = r1*r0*integrate(I11, lower=0, upper=T[1], abs.tol=1e-8)$value
      cov = sigma11
      out = list()
      out$cov = cov; 
      info=NULL
      if (!is.null(n)){info = n * F.entry(T[1]) * cov}
      out$info = info
      return(out)
    } else {
      
      #(1.2) Two weighted log-rank tests at 1 time
      I11 = function(t){
        w1 = f.w(t, f.S = f.S, f.ws0=f.ws[[1]], tau0=tau[1], s.tau0=s.tau[1], rho0=rho[1], gamma0=gamma[1])
        return(w1^2 * F.entry(T[1]-t) * (1 - G.ltfu(t)) * f(t))
      }
      I12 = function(t){
        w1 = f.w(t, f.S = f.S, f.ws0=f.ws[[1]], tau0=tau[1], s.tau0=s.tau[1], rho0=rho[1], gamma0=gamma[1])
        w2 = f.w(t, f.S = f.S, f.ws0=f.ws[[2]], tau0=tau[2], s.tau0=s.tau[2], rho0=rho[2], gamma0=gamma[2])
        return(w1 * w2 * F.entry(T[1]-t) * (1 - G.ltfu(t)) * f(t))
      }
      I22 = function(t){
        w2 = f.w(t, f.S = f.S, f.ws0=f.ws[[2]], tau0=tau[2], s.tau0=s.tau[2], rho0=rho[2], gamma0=gamma[2])
        return(w2^2 * F.entry(T[1]-t) * (1 - G.ltfu(t)) * f(t))
      }
      sigma11 = r1*r0*integrate(I11, lower=0, upper=T[1], abs.tol=1e-8)$value
      sigma12 = r1*r0*integrate(I12, lower=0, upper=T[1], abs.tol=1e-8)$value
      sigma22 = r1*r0*integrate(I22, lower=0, upper=T[1], abs.tol=1e-8)$value
      
      cov = matrix(NA, nrow=2, ncol=2)
      cov[1,1]=sigma11; cov[1,2] = cov[2,1] = sigma12; cov[2,2]=sigma22
      out = list()
      out$cov = cov
      info=NULL
      if (!is.null(n)){info = n * F.entry(T[1]) * cov}
      out$info = info
      return(out)
    }
  } 
  #(2) Two analysis times scenarios
  if (length(T)==2 && T[2] > T[1]) {
    #(2.1) One weighted log-rank test at 2 times
    if(is.null(f.ws[[2]]) && (length(rho)==1 || is.null(rho))){
      I11 = function(t){
        w1 = f.w(t, f.S = f.S, f.ws0=f.ws[[1]], tau0=tau[1], s.tau0=s.tau[1], rho0=rho[1], gamma0=gamma[1])
        return(w1^2 * F.entry(T[1]-t) * (1 - G.ltfu(t)) * f(t))
      }
      I22 = function(t){
        w1 = f.w(t, f.S = f.S, f.ws0=f.ws[[1]], tau0=tau[1], s.tau0=s.tau[1], rho0=rho[1], gamma0=gamma[1])
        return(w1^2 * F.entry(T[2]-t) * (1 - G.ltfu(t)) * f(t))
      }
      sigma11 = r1*r0*integrate(I11, lower=0, upper=T[1], abs.tol=1e-8)$value
      sigma12 = sigma11
      sigma22 = r1*r0*integrate(I22, lower=0, upper=T[2], abs.tol=1e-8)$value
    } else {
    #(2.2) Two weighted log-rank tests at 2 times
      I11 = function(t){
        w1 = f.w(t, f.S = f.S, f.ws0=f.ws[[1]], tau0=tau[1], s.tau0=s.tau[1], rho0=rho[1], gamma0=gamma[1])
        return(w1^2 * F.entry(T[1]-t) * (1 - G.ltfu(t)) * f(t))
      }
      I12 = function(t){
        w1 = f.w(t, f.S = f.S, f.ws0=f.ws[[1]], tau0=tau[1], s.tau0=s.tau[1], rho0=rho[1], gamma0=gamma[1])
        w2 = f.w(t, f.S = f.S, f.ws0=f.ws[[2]], tau0=tau[2], s.tau0=s.tau[2], rho0=rho[2], gamma0=gamma[2])
        return(w1 * w2 * F.entry(T[1]-t) * (1 - G.ltfu(t)) * f(t))
      }
      I22 = function(t){
        w2 = f.w(t, f.S = f.S, f.ws0=f.ws[[2]], tau0=tau[2], s.tau0=s.tau[2], rho0=rho[2], gamma0=gamma[2])
        return(w2^2 * F.entry(T[2]-t) * (1 - G.ltfu(t)) * f(t))
      }
      sigma11 = r1*r0*integrate(I11, lower=0, upper=T[1], abs.tol=1e-8)$value
      sigma12 = r1*r0*integrate(I12, lower=0, upper=T[1], abs.tol=1e-8)$value
      sigma22 = r1*r0*integrate(I22, lower=0, upper=T[2], abs.tol=1e-8)$value
    }
    cov = matrix(NA, nrow=2, ncol=2)
    cov[1,1]=sigma11; cov[1,2] = cov[2,1] = sigma12; cov[2,2]=sigma22
    out = list()
    out$cov = cov
    info=NULL
    if (!is.null(n)){
      info = n * F.entry(T[1]) * cov
      info[2, 2] = n * F.entry(T[2]) * cov[2,2]
    }
    out$info = info
    return(out)
   }
  }

